import React, { useContext } from 'react';
import AdminLayout from '../../components/Layouts/AdminLayout';
import { DataContext } from '../../context/DataContext';
import { AuthContext } from '../../context/AuthContext';
import { ROLES, formatCurrency, formatDate } from '../../utils/helpers';

const Reports = () => {
  const { facilityReports, staffList } = useContext(DataContext);
  const { user } = useContext(AuthContext);

  const isChief = user.role === ROLES.CHIEF_ADMIN;

  return (
    <AdminLayout>
      <div className="p-4 space-y-6">
        <h2 className="text-2xl font-bold">Báo cáo & Thống kê</h2>

        {/* Yêu cầu 3: Báo cáo CSVC */}
        <div className="bg-white p-4 rounded shadow">
          <h3 className="font-bold text-lg mb-3 text-blue-800">Tình hình Cơ sở vật chất</h3>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border">
                <thead>
                    <tr className="bg-blue-50">
                        <th className="p-2 border">Thời gian ghi nhận</th>
                        <th className="p-2 border">Người báo cáo</th>
                        <th className="p-2 border">Thời điểm</th>
                        <th className="p-2 border">Tình trạng</th>
                        <th className="p-2 border">Ghi chú</th>
                    </tr>
                </thead>
                <tbody>
                    {facilityReports.map(r => (
                        <tr key={r.id} className="border-b">
                            <td className="p-2">{formatDate(r.timestamp)}</td>
                            <td className="p-2">{r.reporterName}</td>
                            <td className="p-2 font-semibold">{r.type === 'start' ? 'Đầu giờ' : 'Cuối giờ'}</td>
                            <td className="p-2 text-green-600">Đã kiểm tra</td>
                            <td className="p-2">{r.note || 'Ổn định'}</td>
                        </tr>
                    ))}
                    {facilityReports.length === 0 && <tr><td colSpan="5" className="p-4 text-center">Chưa có dữ liệu</td></tr>}
                </tbody>
            </table>
          </div>
        </div>

        {/* Yêu cầu 5: Tổng thu nhập (Chỉ Chief Admin) */}
        {isChief && (
            <div className="bg-white p-4 rounded shadow border-t-4 border-yellow-500">
                <h3 className="font-bold text-lg mb-3 text-yellow-800">Tổng quan Thu nhập (Dành riêng Chief Admin)</h3>
                <table className="w-full text-sm">
                    <thead>
                        <tr className="bg-yellow-50">
                            <th className="p-2 text-left">Nhân sự</th>
                            <th className="p-2 text-right">Tổng UBI 1</th>
                            <th className="p-2 text-right">Tổng UBI 2</th>
                            <th className="p-2 text-right">Tổng Thù lao</th>
                            <th className="p-2 text-right font-bold">TỔNG CỘNG</th>
                        </tr>
                    </thead>
                    <tbody>
                        {staffList.map(s => {
                            // Giả lập tính toán đơn giản
                            const total = (s.remuneration * (s.ubi1_percent + s.ubi2_percent) / 100) + s.remuneration;
                            return (
                                <tr key={s.id} className="border-b">
                                    <td className="p-2">{s.name}</td>
                                    <td className="p-2 text-right">{s.ubi1_percent}%</td>
                                    <td className="p-2 text-right">{s.ubi2_percent}%</td>
                                    <td className="p-2 text-right">{formatCurrency(s.remuneration)}</td>
                                    <td className="p-2 text-right font-bold text-green-700">{formatCurrency(total)}</td>
                                </tr>
                            )
                        })}
                    </tbody>
                </table>
            </div>
        )}
      </div>
    </AdminLayout>
  );
};

export default Reports;
